export default {
  async fetch(request, env) {
    try {
      const url = new URL(request.url);
      const path = url.pathname;
      
      // Authentication middleware
      if (!await authenticateRequest(request, env)) {
        return new Response(JSON.stringify({ error: 'Unauthorized' }), {
          status: 401,
          headers: { 'Content-Type': 'application/json' }
        });
      }

      // Route handling
      if (path.startsWith('/api/email')) {
        return await handleEmailRequest(request, env);
      } else if (path.startsWith('/api/payment')) {
        return await handlePaymentRequest(request, env);
      } else {
        return new Response(JSON.stringify({ error: 'Not Found' }), {
          status: 404,
          headers: { 'Content-Type': 'application/json' }
        });
      }
    } catch (error) {
      console.error('Worker error:', error);
      return new Response(JSON.stringify({ error: 'Internal Server Error' }), {
        status: 500,
        headers: { 'Content-Type': 'application/json' }
      });
    }
  }
};

async function authenticateRequest(request, env) {
  const authHeader = request.headers.get('Authorization');
  if (!authHeader) return false;
  
  const token = authHeader.replace('Bearer ', '');
  try {
    const decoded = await verifyToken(token, env.JWT_SECRET);
    return !!decoded;
  } catch (error) {
    console.error('Auth error:', error);
    return false;
  }
}

async function verifyToken(token, secret) {
  // Implement JWT verification
  return new Promise((resolve, reject) => {
    // Use crypto.subtle for verification
    resolve({ valid: true });
  });
}

async function handleEmailRequest(request, env) {
  try {
    const body = await request.json();
    
    if (!body.to || !body.subject || !body.html) {
      return new Response(JSON.stringify({ error: 'Missing required fields' }), {
        status: 400,
        headers: { 'Content-Type': 'application/json' }
      });
    }

    const sendGridResponse = await fetch('https://api.sendgrid.com/v3/mail/send', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${env.SENDGRID_API_KEY}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        personalizations: [{
          to: [{ email: body.to }],
          subject: body.subject
        }],
        from: { email: env.FROM_EMAIL },
        content: [{ type: 'text/html', value: body.html }]
      })
    });

    if (!sendGridResponse.ok) {
      throw new Error(`SendGrid error: ${sendGridResponse.status}`);
    }

    return new Response(JSON.stringify({ success: true }), {
      headers: { 'Content-Type': 'application/json' }
    });
  } catch (error) {
    console.error('Email error:', error);
    return new Response(JSON.stringify({ error: 'Failed to send email' }), {
      status: 500,
      headers: { 'Content-Type': 'application/json' }
    });
  }
}

async function handlePaymentRequest(request, env) {
  try {
    const body = await request.json();
    
    if (!body.amount || !body.currency || !body.payment_method_id) {
      return new Response(JSON.stringify({ error: 'Missing required fields' }), {
        status: 400,
        headers: { 'Content-Type': 'application/json' }
      });
    }

    const stripeResponse = await fetch('https://api.stripe.com/v1/payment_intents', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${env.STRIPE_SECRET_KEY}`,
        'Content-Type': 'application/x-www-form-urlencoded'
      },
      body: new URLSearchParams({
        amount: Math.round(body.amount * 100),
        currency: body.currency,
        payment_method: body.payment_method_id,
        confirm: 'true'
      })
    });

    if (!stripeResponse.ok) {
      const error = await stripeResponse.json();
      throw new Error(error.error?.message || 'Stripe error');
    }

    const result = await stripeResponse.json();
    
    return new Response(JSON.stringify({ 
      success: true, 
      payment_intent: result.id,
      status: result.status 
    }), {
      headers: { 'Content-Type': 'application/json' }
    });
  } catch (error) {
    console.error('Payment error:', error);
    return new Response(JSON.stringify({ error: error.message || 'Payment failed' }), {
      status: 400,
      headers: { 'Content-Type': 'application/json' }
    });
  }
}

